func (c *current) onEqualityExpr2(left, op, right any) (any, error) {
	switch op.(string) {
	case "==":
		return &Equality{
			Left:  left.(Node),
			Right: right.(Node),
			Loc:   c.Loc(),
		}, nil
	case "!=":
		return NewInequality(left.(Node), right.(Node), c.Loc()), nil
	default:
		return nil, fmt.Errorf("unknown equality operator: %s", op.(string))
	}
}

